"use client";
import { useState } from "react";

export default function BookingForm() {
    const [bookingCar, setBookingCar] = useState("");
    const [bookingDate, setBookingDate] = useState("");
    const [agreed, setAgreed] = useState(false);
    const [showWarning, setShowWarning] = useState(false);
    const [showConfirm, setShowConfirm] = useState(false);
    const [errorMsg, setErrorMsg] = useState("");

    const carOptions = [
        "Rolls-Royce Phantom",
        "Bentley Continental GT",
        "Lamborghini Urus",
        "Mercedes-Maybach S-Class",
        "Porsche 911 Turbo S"
    ];

    const handleBookingSubmit = (e: React.FormEvent) => {
        e.preventDefault();

        if (!bookingCar || !bookingDate) {
            setErrorMsg("Booking Failed: Please select car and date");
            setShowWarning(true);
            return;
        }

        if (!agreed) {
            setErrorMsg("Booking Failed: Please accept the terms and conditions");
            setShowWarning(true);
            return;
        }

        setShowWarning(false);
        setShowConfirm(true);
    };

    return (
        <>
            <div className="bg-card-bg shadow-sm overflow-hidden border border-border">
                <form onSubmit={handleBookingSubmit} className="p-8 md:p-12 space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                        <div className="space-y-3">
                            <label className="block text-[10px] uppercase tracking-[0.2em] text-muted font-bold ml-2">Booking Model</label>
                            <div className="relative">
                                <select
                                    value={bookingCar}
                                    onChange={(e) => setBookingCar(e.target.value)}
                                    className="w-full bg-card-bg border border-border px-6 py-4 outline-none focus:border-accent focus:ring-1 focus:ring-accent transition-all appearance-none cursor-pointer text-sm text-foreground font-semibold"
                                >
                                    <option value="" className="text-muted">Select a car for booking</option>
                                    {carOptions.map(car => <option key={car} value={car} className="text-foreground">{car}</option>)}
                                </select>
                                <div className="absolute right-5 top-1/2 -translate-y-1/2 pointer-events-none text-foreground">
                                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" viewBox="0 0 256 256"><path d="M213.66,101.66l-80,80a8,8,0,0,1-11.32,0l-80-80a8,8,0,0,1,11.32-11.32L128,164.69l74.34-74.35a8,8,0,0,1,11.32,11.32Z"></path></svg>
                                </div>
                            </div>
                        </div>

                        <div className="space-y-3">
                            <label className="block text-[10px] uppercase tracking-[0.2em] text-muted font-bold ml-2">Booking Date</label>
                            <input
                                type="date"
                                value={bookingDate}
                                onChange={(e) => setBookingDate(e.target.value)}
                                className="w-full bg-card-bg border border-border px-6 py-4 outline-none focus:border-accent focus:ring-1 focus:ring-accent transition-all cursor-pointer text-sm text-foreground font-semibold"
                            />
                        </div>
                    </div>

                    <div className="flex items-center gap-3 ml-2">
                        <input
                            type="checkbox"
                            id="terms"
                            checked={agreed}
                            onChange={(e) => setAgreed(e.target.checked)}
                            className="w-4 h-4 accent-accent cursor-pointer"
                        />
                        <label htmlFor="terms" className="text-[11px] text-muted uppercase tracking-widest cursor-pointer select-none font-medium">
                            I agree to the terms and booking conditions
                        </label>
                    </div>

                    {showWarning && (
                        <div className="flex items-center gap-3 bg-red-50 text-red-700 p-5 rounded-2xl border border-red-200 font-serif">
                            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="currentColor" viewBox="0 0 256 256"><path d="M128,24A104,104,0,1,0,232,128,104.11,104.11,0,0,0,128,24Zm0,192a88,88,0,1,1,88-88A88.1,88.1,0,0,1,128,216Zm-8-80V80a8,8,0,0,1,16,0v56a8,8,0,0,1-16,0Zm20,36a12,12,0,1,1-12-12A12,12,0,0,1,140,172Z"></path></svg>
                            <span className="text-xs font-bold uppercase tracking-wider">{errorMsg}</span>
                        </div>
                    )}

                    <button
                        type="submit"
                        className="w-full bg-accent text-white py-4 font-semibold uppercase text-[11px] tracking-[0.3em] hover:opacity-90 transition-all duration-300 shadow-sm active:scale-[0.99] cursor-pointer"
                    >
                        Request Booking
                    </button>
                </form>
            </div>

            {showConfirm && (
                <div className="fixed inset-0 z-150 flex items-center justify-center p-6 bg-black/70 backdrop-blur-sm">
                    <div className="bg-card-bg max-w-sm w-full border border-border p-10 text-center shadow-lg">
                        <div className="w-20 h-20 bg-[#efe7dc] text-accent rounded-full flex items-center justify-center mx-auto mb-6 border border-border">
                            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" fill="currentColor" viewBox="0 0 256 256"><path d="M229.66,77.66l-128,128a8,8,0,0,1-11.32,0l-56-56a8,8,0,0,1,11.32-11.32L100,192.69,218.34,74.34a8,8,0,0,1,11.32,11.32Z"></path></svg>
                        </div>
                        <h3 className="text-3xl font-bold mb-3 text-foreground">Booking Confirmed</h3>
                        <p className="text-muted text-[11px] uppercase tracking-widest mb-10 leading-loose">
                            Your reservation for <span className="text-foreground font-bold">{bookingCar}</span> <br /> is secured for {bookingDate}
                        </p>
                        <button
                            onClick={() => setShowConfirm(false)}
                            className="w-full bg-accent text-white py-3 font-semibold text-[10px] uppercase tracking-widest hover:opacity-90 transition-all cursor-pointer"
                        >
                            Complete Booking
                        </button>
                    </div>
                </div>
            )}
        </>
    );
}